<template>  <div class="login-container">    <el-card class="login-card" shadow="hover">      <template #header>        <div class="login-header">          <h2>RBAC 管理系统</h2>          <p>请登录您的账户</p>        </div>      </template>      <el-form        ref="loginFormRef"        :model="loginForm"        :rules="loginRules"        label-width="0px"        class="login-form"      >        <el-form-item prop="username">          <el-input            v-model="loginForm.username"            placeholder="请输入用户名"            size="large"            :prefix-icon="User"          />        </el-form-item>        <el-form-item prop="password">          <el-input            v-model="loginForm.password"            type="password"            placeholder="请输入密码"            size="large"            :prefix-icon="Lock"            @keyup.enter="handleLogin"          />        </el-form-item>        <el-form-item>          <el-button            type="primary"            size="large"            class="login-button"            :loading="loading"            @click="handleLogin"          >            登录          </el-button>        </el-form-item>        <el-form-item>          <el-button            type="text"            size="small"            @click="showRegister = true"          >            还没有账户？点击注册          </el-button>        </el-form-item>      </el-form>    </el-card>    <!-- 注册对话框 -->    <el-dialog      v-model="showRegister"      title="用户注册"      width="400px"    >      <el-form        ref="registerFormRef"        :model="registerForm"        :rules="registerRules"        label-width="80px"      >        <el-form-item label="用户名" prop="username">          <el-input            v-model="registerForm.username"            placeholder="请输入用户名"          />        </el-form-item>        <el-form-item label="密码" prop="password">          <el-input            v-model="registerForm.password"            type="password"            placeholder="请输入密码"          />        </el-form-item>        <el-form-item label="确认密码" prop="confirmPassword">          <el-input            v-model="registerForm.confirmPassword"            type="password"            placeholder="请再次输入密码"          />        </el-form-item>      </el-form>      <template #footer>        <span class="dialog-footer">          <el-button @click="showRegister = false">取消</el-button>          <el-button type="primary" :loading="registerLoading" @click="handleRegister">            注册          </el-button>        </span>      </template>    </el-dialog>  </div></template><script>import { ref, reactive } from 'vue'import { useRouter } from 'vue-router'import { useAuthStore } from '../stores/auth'import { ElMessage } from 'element-plus'// import { User, Lock } from '@element-plus/icons-vue'export default {  name: 'LoginView',  components: {    // User,    // Lock  },  setup() {    const router = useRouter()    const authStore = useAuthStore()    const loginFormRef = ref()    const registerFormRef = ref()    const loginForm = reactive({      username: '',      password: ''    })    const registerForm = reactive({      username: '',      password: '',      confirmPassword: ''    })    const loading = ref(false)    const registerLoading = ref(false)    const showRegister = ref(false)    const loginRules = {      username: [        { required: true, message: '请输入用户名', trigger: 'blur' }      ],      password: [        { required: true, message: '请输入密码', trigger: 'blur' }      ]    }    const registerRules = {      username: [        { required: true, message: '请输入用户名', trigger: 'blur' },        { min: 3, max: 20, message: '用户名长度在 3 到 20 个字符', trigger: 'blur' }      ],      password: [        { required: true, message: '请输入密码', trigger: 'blur' },        { min: 6, message: '密码长度不能少于 6 个字符', trigger: 'blur' }      ],      confirmPassword: [        { required: true, message: '请再次输入密码', trigger: 'blur' },        {          validator: (rule, value, callback) => {            if (value !== registerForm.password) {              callback(new Error('两次输入密码不一致'))            } else {              callback()            }          },          trigger: 'blur'        }      ]    }    const handleLogin = async () => {      try {        await loginFormRef.value.validate()        loading.value = true        const result = await authStore.login(loginForm)        if (result.success) {          ElMessage.success('登录成功')          router.push('/')        } else {          ElMessage.error(result.message)        }      } catch (error) {        console.error('Login validation error:', error)      } finally {        loading.value = false      }    }    const handleRegister = async () => {      try {        await registerFormRef.value.validate()        registerLoading.value = true        const result = await authStore.register(registerForm)        if (result.success) {          ElMessage.success(result.message)          showRegister.value = false          registerForm.username = ''          registerForm.password = ''          registerForm.confirmPassword = ''        } else {          ElMessage.error(result.message)        }      } catch (error) {        console.error('Register validation error:', error)      } finally {        registerLoading.value = false      }    }    return {      loginFormRef,      registerFormRef,      loginForm,      registerForm,      loading,      registerLoading,      showRegister,      loginRules,      registerRules,      handleLogin,      handleRegister    }  }}</script><style scoped>.login-container {  display: flex;  justify-content: center;  align-items: center;  height: 100vh;  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);}.login-card {  width: 400px;  max-width: 90%;}.login-header {  text-align: center;}.login-header h2 {  margin: 0 0 10px 0;  color: #409eff;}.login-header p {  margin: 0;  color: #666;}.login-form {  padding: 20px 0;}.login-button {  width: 100%;}.dialog-footer {  text-align: right;}</style>